import React, { useState, useEffect } from 'react';
import { useNavigate, Link } from 'react-router-dom';
import api from '../utils/api';

export default function Register() {
  const [form, setForm] = useState({ account_type: 'student', member_id: '', name: '', email: '', password: '', confirm_password: '', department: '', batch: '', mobile: '', address: '', gender: '' });
  const [error, setError]     = useState('');
  const [success, setSuccess] = useState('');
  const [loading, setLoading] = useState(false);
  const [showPass, setShowPass]   = useState(false);
  const [showPass2, setShowPass2] = useState(false);
  const [scale, setScale] = useState(1);
  const navigate = useNavigate();

  const set = (k: string, v: string) => setForm(f => ({ ...f, [k]: v }));

  /* Ken Burns */
  useEffect(() => {
    let dir = 1;
    const id = setInterval(() => {
      setScale(s => {
        const n = s + dir * 0.0007;
        if (n >= 1.1) dir = -1;
        if (n <= 1.0) dir = 1;
        return parseFloat(n.toFixed(4));
      });
    }, 30);
    return () => clearInterval(id);
  }, []);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setError(''); setSuccess('');
    if (form.password !== form.confirm_password) { setError('Passwords do not match!'); return; }
    if (form.password.length < 6) { setError('Password must be at least 6 characters!'); return; }
    setLoading(true);
    try {
      await api.post('/auth/register', form);
      setSuccess('Registration successful! Please wait for librarian approval.');
      setTimeout(() => navigate('/login'), 3000);
    } catch (e: any) {
      setError(e.response?.data?.message || 'Registration failed');
    } finally { setLoading(false); }
  };

  const inp: React.CSSProperties = {
    width: '100%', padding: '12px 14px',
    background: 'rgba(255,255,255,0.07)',
    border: '1.5px solid rgba(255,255,255,0.12)',
    borderRadius: 11, fontSize: 13,
    color: '#fff', fontFamily: 'inherit',
    outline: 'none', boxSizing: 'border-box',
    transition: 'border-color .2s, box-shadow .2s',
  };
  const lbl: React.CSSProperties = {
    display: 'block', fontSize: 10, fontWeight: 700,
    color: 'rgba(255,255,255,0.45)', marginBottom: 7,
    letterSpacing: '1px', textTransform: 'uppercase',
  };

  return (
    <div style={{ minHeight: '100vh', width: '100%', position: 'relative', display: 'flex', alignItems: 'center', justifyContent: 'center', fontFamily: "'DM Sans', sans-serif", overflow: 'hidden', padding: '24px 20px' }}>
      <style>{`
        @import url('https://fonts.googleapis.com/css2?family=Playfair+Display:wght@600;700&family=DM+Sans:wght@400;500;600;700&display=swap');
        * { box-sizing: border-box; }
        .ri:focus { border-color: #c9a84c !important; box-shadow: 0 0 0 3px rgba(201,168,76,0.2) !important; }
        .ri::placeholder { color: rgba(255,255,255,0.2) !important; }
        .rbtn:hover:not(:disabled) { background: #d4b55a !important; transform: translateY(-2px); box-shadow: 0 10px 28px rgba(201,168,76,0.4) !important; }
        .rbtn:disabled { opacity:.65; cursor:not-allowed; }
        .card-up { animation: cUp .55s cubic-bezier(.16,1,.3,1) forwards; }
        @keyframes cUp { from { opacity:0; transform:translateY(28px); } to { opacity:1; transform:translateY(0); } }
        .type-btn { transition: all .2s !important; }
        .type-btn:hover { border-color: rgba(201,168,76,0.5) !important; }
      `}</style>

      {/* BG */}
      <div style={{ position:'absolute', inset:0, zIndex:0, backgroundImage:'url(/library-bg.jpg)', backgroundSize:'cover', backgroundPosition:'center', transform:`scale(${scale})`, filter:'brightness(0.4)', willChange:'transform', transition:'transform .1s linear' }} />
      {/* Vignette */}
      <div style={{ position:'absolute', inset:0, zIndex:1, background:'radial-gradient(ellipse at center, transparent 20%, rgba(0,0,0,0.7) 100%)' }} />

      {/* Card */}
      <div className="card-up" style={{ position:'relative', zIndex:2, width:'100%', maxWidth:520, display:'flex', flexDirection:'column', alignItems:'center' }}>

        {/* Header */}
        <p style={{ fontSize:10, fontWeight:700, letterSpacing:'2px', color:'rgba(255,255,255,0.4)', textTransform:'uppercase', marginBottom:8, textAlign:'center' }}>
          Bangladesh Army University of Science and Technology
        </p>
        <h1 style={{ fontFamily:"'Playfair Display',serif", fontSize:30, fontWeight:700, color:'#fff', margin:'0 0 4px', textAlign:'center' }}>LibraryMS</h1>
        <div style={{ width:36, height:2, background:'linear-gradient(90deg,transparent,#c9a84c,transparent)', margin:'0 auto 24px' }} />

        {/* Glass box */}
        <div style={{ width:'100%', background:'rgba(15,15,25,0.68)', backdropFilter:'blur(28px)', WebkitBackdropFilter:'blur(28px)', border:'1px solid rgba(255,255,255,0.1)', borderRadius:22, padding:'30px 30px 24px', boxShadow:'0 32px 80px rgba(0,0,0,0.5), inset 0 1px 0 rgba(255,255,255,0.07)' }}>

          <h2 style={{ fontSize:20, fontWeight:700, color:'#fff', margin:'0 0 4px', textAlign:'center' }}>Create Account</h2>
          <p style={{ fontSize:12, color:'rgba(255,255,255,0.35)', margin:'0 0 22px', textAlign:'center' }}>Register to access the library</p>

          {error   && <div style={{ background:'rgba(220,38,38,0.15)', border:'1px solid rgba(220,38,38,0.35)', color:'#fca5a5', padding:'10px 14px', borderRadius:10, fontSize:13, marginBottom:16, display:'flex', alignItems:'center', gap:8 }}><span>⚠</span>{error}</div>}
          {success && <div style={{ background:'rgba(5,150,105,0.15)', border:'1px solid rgba(5,150,105,0.35)', color:'#6ee7b7', padding:'10px 14px', borderRadius:10, fontSize:13, marginBottom:16, display:'flex', alignItems:'center', gap:8 }}><span>✓</span>{success}</div>}

          <form onSubmit={handleSubmit}>
            {/* Account Type */}
            <div style={{ marginBottom:18 }}>
              <label style={lbl}>Account Type *</label>
              <div style={{ display:'flex', gap:8 }}>
                {['student','staff'].map(type => (
                  <button key={type} type="button" className="type-btn" onClick={() => set('account_type', type)}
                    style={{ flex:1, padding:'10px', border:`1.5px solid ${form.account_type===type ? '#c9a84c' : 'rgba(255,255,255,0.12)'}`, borderRadius:10, background: form.account_type===type ? 'rgba(201,168,76,0.18)' : 'rgba(255,255,255,0.05)', color: form.account_type===type ? '#c9a84c' : 'rgba(255,255,255,0.5)', fontSize:13, fontWeight:600, cursor:'pointer', fontFamily:'inherit', textTransform:'capitalize' }}>
                    {type==='student' ? '🎓' : '👨‍💼'} {type.charAt(0).toUpperCase()+type.slice(1)}
                  </button>
                ))}
              </div>
            </div>

            <div style={{ display:'grid', gridTemplateColumns:'1fr 1fr', gap:12 }}>
              <div>
                <label style={lbl}>{form.account_type==='student' ? 'Student ID' : 'Staff ID'} *</label>
                <input className="ri" style={inp} value={form.member_id} onChange={e=>set('member_id',e.target.value)} placeholder={form.account_type==='student'?'e.g. 20210101':'e.g. 10001'} required />
              </div>
              <div>
                <label style={lbl}>Full Name *</label>
                <input className="ri" style={inp} value={form.name} onChange={e=>set('name',e.target.value)} placeholder="Your full name" required />
              </div>
              <div>
                <label style={lbl}>Department *</label>
                <input className="ri" style={inp} value={form.department} onChange={e=>set('department',e.target.value)} placeholder="e.g. CSE" required />
              </div>
              {form.account_type==='student' ? (
                <div>
                  <label style={lbl}>Batch *</label>
                  <input className="ri" style={inp} value={form.batch} onChange={e=>set('batch',e.target.value)} placeholder="e.g. 2021" required />
                </div>
              ) : <div />}
              <div>
                <label style={lbl}>Mobile *</label>
                <input className="ri" style={inp} value={form.mobile} onChange={e=>set('mobile',e.target.value)} placeholder="01XXXXXXXXX" required />
              </div>
              <div>
                <label style={lbl}>Gender *</label>
                <select className="ri" style={{ ...inp, appearance:'none' }} value={form.gender} onChange={e=>set('gender',e.target.value)} required>
                  <option value="" style={{ background:'#1a1a2e' }}>Select gender</option>
                  <option value="male" style={{ background:'#1a1a2e' }}>Male</option>
                  <option value="female" style={{ background:'#1a1a2e' }}>Female</option>
                  <option value="other" style={{ background:'#1a1a2e' }}>Other</option>
                </select>
              </div>
              <div style={{ gridColumn:'1/-1' }}>
                <label style={lbl}>Email Address *</label>
                <input className="ri" style={inp} type="email" value={form.email} onChange={e=>set('email',e.target.value.toLowerCase())} placeholder="your@email.com" required />
              </div>
              <div style={{ position:'relative' }}>
                <label style={lbl}>Password *</label>
                <input className="ri" style={{ ...inp, paddingRight:42 }} type={showPass?'text':'password'} value={form.password} onChange={e=>set('password',e.target.value)} placeholder="Min 6 characters" required />
                <button type="button" onClick={()=>setShowPass(v=>!v)} style={{ position:'absolute', right:12, bottom:10, background:'none', border:'none', color:'rgba(255,255,255,0.35)', cursor:'pointer', fontSize:16, padding:2 }}>{showPass?'🙈':'👁'}</button>
              </div>
              <div style={{ position:'relative' }}>
                <label style={lbl}>Confirm Password *</label>
                <input className="ri" style={{ ...inp, paddingRight:42 }} type={showPass2?'text':'password'} value={form.confirm_password} onChange={e=>set('confirm_password',e.target.value)} placeholder="Repeat password" required />
                <button type="button" onClick={()=>setShowPass2(v=>!v)} style={{ position:'absolute', right:12, bottom:10, background:'none', border:'none', color:'rgba(255,255,255,0.35)', cursor:'pointer', fontSize:16, padding:2 }}>{showPass2?'🙈':'👁'}</button>
              </div>
              <div style={{ gridColumn:'1/-1' }}>
                <label style={lbl}>Address</label>
                <textarea className="ri" style={{ ...inp, minHeight:72, resize:'vertical' }} value={form.address} onChange={e=>set('address',e.target.value)} placeholder="Your full address (optional)" />
              </div>
            </div>

            <button type="submit" disabled={loading} className="rbtn"
              style={{ width:'100%', padding:'13px', background:'#c9a84c', color:'#1a1a2e', border:'none', borderRadius:12, fontSize:14, fontWeight:700, cursor:'pointer', fontFamily:'inherit', marginTop:18, transition:'all .25s', boxShadow:'0 4px 18px rgba(201,168,76,0.3)', letterSpacing:'0.3px' }}>
              {loading ? 'Creating account...' : 'Create Account →'}
            </button>
          </form>

          <p style={{ textAlign:'center', fontSize:12, color:'rgba(255,255,255,0.3)', marginTop:16 }}>
            Already have an account?{' '}
            <Link to="/login" style={{ color:'#c9a84c', fontWeight:600, textDecoration:'none' }}>Sign in</Link>
          </p>

          <div style={{ marginTop:16, background:'rgba(201,168,76,0.08)', border:'1px solid rgba(201,168,76,0.2)', borderRadius:10, padding:'10px 14px', display:'flex', alignItems:'flex-start', gap:8 }}>
            <span style={{ fontSize:14, flexShrink:0, marginTop:1 }}>⚠️</span>
            <p style={{ fontSize:11, color:'rgba(255,255,255,0.4)', margin:0, lineHeight:1.6 }}>
              After registration, your account needs <strong style={{ color:'#c9a84c' }}>librarian approval</strong> before you can login.
            </p>
          </div>
        </div>

        <p style={{ fontSize:10, color:'rgba(255,255,255,0.18)', marginTop:16, letterSpacing:'1.5px', textTransform:'uppercase', textAlign:'center' }}>
          BAUST · Library Management System
        </p>
      </div>
    </div>
  );
}
